try {
  const wd = sim.worldData
  const NB = 16
  if (!wd.__tv || wd.__tv.v !== 2) {
    wd.__tv = { v: 2, ch: 1, sw: 0, held: 0, sHeld: 0, ct: 0, door: 0, laugh: 0, lseq: 0, lq: 0,
      cast: [
        { x: -0.42, tx: -0.42, pose: 2, face: 1, talk: 0, row: 0.0, st: 'sit', t: 4, partner: -1, knocked: 0 },
        { x: 0.47, tx: 0.47, pose: 0, face: 1, talk: 0, row: 0.012, st: 'kitchen', t: 5, partner: -1, knocked: 0 },
        { x: 0.10, tx: 0.10, pose: 0, face: -1, talk: 0, row: -0.012, st: 'idle', t: 2, partner: -1, knocked: 0 },
        { x: 1.10, tx: 1.10, pose: 3, face: -1, talk: 0, row: 0.024, st: 'out', t: 7, partner: -1, knocked: 0 },
      ],
      pong: { bx: 0, by: 0, vx: 0.9, vy: 0.5, pa: 0, pb: 0, sa: 0, sb: 0 },
      boids: Array.from({ length: NB }, (_, i) => ({ x: Math.sin(i * 2.1) * 0.5, y: Math.cos(i * 1.7) * 0.5, vx: 0.2, vy: 0.1 })),
      tgt: { x: 0, y: 0, t: 0 } }
  }
  const G = wd.__tv
  const pdt = Math.min(dt, 0.05)

  // channel change: click anywhere or space
  const want = (wd.mouse_down && !G.held) || (wd.key_space && !G.sHeld)
  if (wd.mouse_down) G.held = 1; else G.held = 0
  if (wd.key_space) G.sHeld = 1; else G.sHeld = 0
  if (want) {
    G.ch = (G.ch + 1) % 5
    G.sw = 1
    wd.__play_sound = [
      { frequency: 1200, duration: 0.03, volume: 0.25, type: 'square' },
      { frequency: 90, duration: 0.15, volume: 0.2, type: 'sawtooth' },
    ]
  }
  G.sw = Math.max(0, G.sw - 2.2 * pdt)

  // ── ALGORITHM 1: Pong plays itself ──
  const P = G.pong
  P.bx += P.vx * pdt; P.by += P.vy * pdt
  if (P.by > 0.92 || P.by < -0.92) { P.vy = -P.vy; P.by = Math.sign(P.by) * 0.92 }
  const chase = (pad, ty) => pad + Math.max(-1.3 * pdt, Math.min(1.3 * pdt, ty - pad))
  P.pa = chase(P.pa, P.vx < 0 ? P.by : P.by * 0.3)
  P.pb = chase(P.pb, P.vx > 0 ? P.by : P.by * 0.3)
  if (P.bx < -0.82 && Math.abs(P.by - P.pa) < 0.19 && P.vx < 0) { P.vx = -P.vx * 1.04; P.vy += (P.by - P.pa) * 2.0; P.bx = -0.82 }
  if (P.bx > 0.82 && Math.abs(P.by - P.pb) < 0.19 && P.vx > 0) { P.vx = -P.vx * 1.04; P.vy += (P.by - P.pb) * 2.0; P.bx = 0.82 }
  if (Math.abs(P.bx) > 1.05) {
    if (P.bx > 0) P.sa = Math.min(5, P.sa + 1); else P.sb = Math.min(5, P.sb + 1)
    if (P.sa >= 5 || P.sb >= 5) { P.sa = 0; P.sb = 0 }
    P.bx = 0; P.by = 0; P.vx = Math.sign(-P.bx || (Math.random() < 0.5 ? 1 : -1)) * 0.9; P.vy = 0.5
    if (G.ch === 2) wd.__play_sound = { frequency: 220, duration: 0.12, volume: 0.25, type: 'square' }
  }
  const spd = Math.hypot(P.vx, P.vy)
  if (spd > 2.2) { P.vx *= 2.2 / spd; P.vy *= 2.2 / spd }

  // ── ALGORITHM 2: boids murmuration ──
  G.tgt.t -= pdt
  if (G.tgt.t <= 0) { G.tgt = { x: (Math.sin(Date.now ? 0 : 0) || Math.sin(G.sw * 7 + P.bx * 13)) * 0.6, y: Math.sin(P.by * 11 + G.ch * 3) * 0.5, t: 2.5 } }
  let cx = 0, cy = 0
  for (const b of G.boids) { cx += b.x; cy += b.y }
  cx /= NB; cy /= NB
  for (const b of G.boids) {
    // cohesion + target + separation + alignment-lite
    b.vx += ((cx - b.x) * 0.4 + (G.tgt.x - b.x) * 0.5) * pdt
    b.vy += ((cy - b.y) * 0.4 + (G.tgt.y - b.y) * 0.5) * pdt
    for (const o of G.boids) {
      if (o === b) continue
      const dx = b.x - o.x, dy = b.y - o.y
      const d2 = dx * dx + dy * dy
      if (d2 < 0.008 && d2 > 1e-6) { b.vx += dx / d2 * 0.0022 * pdt * 60; b.vy += dy / d2 * 0.0022 * pdt * 60 }
    }
    const sp = Math.hypot(b.vx, b.vy) || 1
    const want2 = 0.55
    b.vx *= 1 + (want2 - sp) / sp * 0.08
    b.vy *= 1 + (want2 - sp) / sp * 0.08
    b.x += b.vx * pdt; b.y += b.vy * pdt
    if (Math.abs(b.x) > 0.95) { b.vx -= Math.sign(b.x) * 1.5 * pdt }
    if (Math.abs(b.y) > 0.9) { b.vy -= Math.sign(b.y) * 1.5 * pdt }
  }

  // ── ALGORITHM 3: the sitcom — four lives moving through behavior zones ──
  G.ct += pdt
  G.laugh = Math.max(0, G.laugh - 1.1 * pdt)
  G.door = Math.max(0, G.door - 0.55 * pdt)
  if (G.lseq > 0) {
    G.lq -= pdt
    if (G.lq <= 0) {
      if (G.ch === 4) wd.__play_sound = { frequency: 280 + G.lseq * 55 + Math.random() * 40, duration: 0.07, volume: 0.22, type: 'square' }
      G.lq = 0.11; G.lseq--
    }
  }
  const SEATS = [-0.42, -0.20]
  const CAST = G.cast
  for (let i = 0; i < 4; i++) {
    const c = CAST[i]
    c.t -= pdt
    if (c.st === 'walk') {
      const dw = c.tx - c.x
      c.face = dw > 0 ? 1 : -1
      c.x += Math.sign(dw) * Math.min(Math.abs(dw), 0.16 * pdt)
      c.pose = 1
      c.talk = 0
      if (Math.abs(dw) < 0.006) {
        c.st = c.next; c.t = 2.5 + Math.random() * 4
        if (c.st === 'sit') { c.pose = 2; c.face = c.x < -0.31 ? 1 : -1 }
        else if (c.st === 'out') { c.pose = 3; G.door = 1; c.t = 6 + Math.random() * 12 }
        else { c.pose = 0 }
        if (c.st === 'chat') c.t = 5 + Math.random() * 5
        if (c.st === 'window') c.face = -1
        if (c.st === 'kitchen') c.face = 1
      }
      continue
    }
    if (c.st === 'chat') {
      const pr = CAST[c.partner]
      if (!pr || pr.st !== 'chat') { c.st = 'idle'; c.partner = -1; c.talk = 0; c.t = 2; continue }
      c.face = pr.x > c.x ? 1 : -1
      const tk = Math.floor(G.ct / 1.4) % 2
      c.talk = ((i < c.partner) ? tk === 0 : tk === 1) ? 1 : 0
      if (c.t <= 0 && i < c.partner) {
        // the punchline lands
        G.laugh = 1; G.lseq = 5; G.lq = 0
        pr.st = 'idle'; pr.talk = 0; pr.t = 2 + Math.random() * 3; pr.partner = -1
        c.st = 'idle'; c.talk = 0; c.t = 2 + Math.random() * 3; c.partner = -1
      }
      continue
    }
    if (c.st === 'out') {
      c.talk = 0
      if (c.t <= 0) {
        if (!c.knocked) {
          c.knocked = 1; c.t = 1.1
          if (G.ch === 4) wd.__play_sound = [{ frequency: 130, duration: 0.05, volume: 0.3, type: 'square' }, { frequency: 118, duration: 0.05, volume: 0.28, type: 'square' }]
          continue
        }
        c.knocked = 0; G.door = 1
        c.x = 0.84; c.st = 'walk'; c.pose = 1
        c.tx = -0.05 + Math.random() * 0.35; c.next = 'idle'
        if (G.ch === 4) wd.__play_sound = { frequency: 520, duration: 0.1, volume: 0.18, type: 'triangle' }
      }
      continue
    }
    // standing zones: when the timer runs out, pick the next scene beat
    c.talk = 0
    if (c.t <= 0) {
      const r = Math.random()
      if (r < 0.30) {
        let j = -1
        for (let k = 0; k < 4; k++) {
          const o = CAST[k]
          if (k !== i && o.partner < 0 && o.pose !== 3 && o.st !== 'walk' && o.st !== 'chat' && o.st !== 'out') { j = k; break }
        }
        if (j >= 0) {
          const o = CAST[j]
          const mx2 = Math.max(-0.55, Math.min(0.6, (c.x + o.x) / 2))
          c.partner = j; o.partner = i
          c.st = 'walk'; c.tx = mx2 - 0.055; c.next = 'chat'
          o.st = 'walk'; o.tx = mx2 + 0.055; o.next = 'chat'
          if (o.pose === 2) o.pose = 1
        } else { c.t = 2 }
      }
      else if (r < 0.50) { c.st = 'walk'; c.tx = SEATS[i % 2] + (Math.random() - 0.5) * 0.03; c.next = 'sit' }
      else if (r < 0.66) { c.st = 'walk'; c.tx = 0.44; c.next = 'kitchen' }
      else if (r < 0.80) { c.st = 'walk'; c.tx = -0.62; c.next = 'window' }
      else if (r < 0.88 && i === 3) { c.st = 'walk'; c.tx = 0.82; c.next = 'out' }
      else { c.st = 'walk'; c.tx = -0.15 + Math.random() * 0.45; c.next = 'idle' }
    }
  }

  const u = [G.ch, G.sw, G.door, P.bx, P.by, P.pa, P.pb, P.sa, P.sb, 0]
  for (const b of G.boids) u.push(b.x, b.y)
  for (const c of G.cast) u.push(c.x, c.pose, c.face, c.talk, c.row)
  u.push(G.laugh)
  wd.gpuUniforms = u
  wd.hud = [
    { id: 'tv_ch', type: 'text', x: '14px', y: '12px', text: 'CH ' + (G.ch + 1) + '  \u00b7  ' + ['STATIC', 'PLASMA', 'PONG', 'BOIDS', 'SITCOM'][G.ch], color: '#c9b370', fontSize: '13px' },
    { id: 'tv_hint', type: 'text', x: '14px', bottom: '12px', text: 'click / space: change channel', color: '#6f8f8a', fontSize: '12px' },
  ]
} catch (e) { /* keep the sim alive */ }

visualTypes.wgsl:
const NC_CELL: f32 = 9.0;

struct NCHit { t: f32, kind: i32, n: vec3f, cell: vec2f };

fn nc_mode() -> f32 { return uni(15); }   // 0 endless · 1 district

fn nc_isStreet(cell: vec2f) -> bool {
  if (nc_mode() > 0.5) {                  // district: finite table, open beyond
    if (cell.x < -5.5 || cell.x > 4.5 || cell.y < -5.5 || cell.y > 4.5) { return true; }
  }
  if (cell.x == 0.0) { return true; }
  if (abs(cell.y - 5.0 * round(cell.y / 5.0)) < 0.5) { return true; }
  return false;
}

fn nc_dims(cell: vec2f) -> vec3f {
  let r = hash22(cell);
  let h  = 6.0 + r.x * 40.0;
  let bw = NC_CELL * 0.5 * (0.72 + r.y * 0.20);
  let bd = NC_CELL * 0.5 * (0.72 + fract(r.y * 7.31 + r.x) * 0.20);
  return vec3f(h, bw, bd);
}

fn nc_ball() -> vec3f { return vec3f(uni(1), uni(2), uni(3)); }

fn nc_sphereT(ro: vec3f, rd: vec3f, c: vec3f, r: f32) -> f32 {
  let oc = ro - c;
  let b = dot(oc, rd);
  let cc = dot(oc, oc) - r * r;
  let h = b * b - cc;
  if (h < 0.0) { return -1.0; }
  return -b - sqrt(h);
}

fn nc_traceCity(ro: vec3f, rd: vec3f, maxd: f32, maxCells: i32) -> NCHit {
  var best: NCHit;
  best.t = maxd; best.kind = -1; best.n = vec3f(0.0, 1.0, 0.0); best.cell = vec2f(0.0, 0.0);

  if (rd.y < -1.0e-4) {
    let tg = -ro.y / rd.y;
    if (tg > 0.0 && tg < best.t) { best.t = tg; best.kind = 0; best.n = vec3f(0.0, 1.0, 0.0); }
  }

  var cell = floor(vec2f(ro.x, ro.z) / NC_CELL);
  let stepDir = sign(vec2f(rd.x, rd.z));
  let cellMin = cell * NC_CELL;

  var tMaxX = 1.0e9;  var tMaxZ = 1.0e9;
  var tDeltaX = 1.0e9; var tDeltaZ = 1.0e9;
  if (abs(rd.x) > 1.0e-6) {
    let bx = select(cellMin.x, cellMin.x + NC_CELL, rd.x > 0.0);
    tMaxX = (bx - ro.x) / rd.x;   tDeltaX = NC_CELL / abs(rd.x);
  }
  if (abs(rd.z) > 1.0e-6) {
    let bz = select(cellMin.y, cellMin.y + NC_CELL, rd.z > 0.0);
    tMaxZ = (bz - ro.z) / rd.z;   tDeltaZ = NC_CELL / abs(rd.z);
  }

  var tEnter = 0.0;
  for (var k = 0; k < maxCells; k = k + 1) {
    if (!nc_isStreet(cell)) {
      let dm = nc_dims(cell);
      let c = vec3f((cell.x + 0.5) * NC_CELL, dm.x * 0.5, (cell.y + 0.5) * NC_CELL);
      let half = vec3f(dm.y, dm.x * 0.5, dm.z);
      let m = 1.0 / rd;
      let nrm = m * (ro - c);
      let kk = abs(m) * half;
      let t1 = -nrm - kk;
      let t2 = -nrm + kk;
      let tN = max(max(t1.x, t1.y), t1.z);
      let tF = min(min(t2.x, t2.y), t2.z);
      if (tF >= tN && tF > 0.0) {
        let th = select(tN, 0.001, tN < 0.0);
        if (th < best.t) {
          best.t = th; best.kind = 1; best.cell = cell;
          best.n = -sign(rd) * step(t1.yzx, t1.xyz) * step(t1.zxy, t1.xyz);
        }
      }
    }
    if (tMaxX < tMaxZ) { tEnter = tMaxX; tMaxX = tMaxX + tDeltaX; cell.x = cell.x + stepDir.x; }
    else              { tEnter = tMaxZ; tMaxZ = tMaxZ + tDeltaZ; cell.y = cell.y + stepDir.y; }
    if (tEnter > best.t || tEnter > maxd) { break; }
  }
  return best;
}

fn nc_sky(rd: vec3f) -> vec3f {
  let y = max(rd.y, 0.0);
  var c = mix(vec3f(0.050, 0.060, 0.110), vec3f(0.008, 0.012, 0.035), pow(y, 0.5));
  c += vec3f(0.28, 0.13, 0.05) * exp(-max(rd.y, 0.0) * 5.5);
  let md = normalize(vec3f(-0.45, 0.42, 1.0));
  let m = max(dot(rd, md), 0.0);
  c += vec3f(0.90, 0.92, 0.98) * pow(m, 3000.0) * 3.0;
  c += vec3f(0.30, 0.34, 0.44) * pow(m, 30.0) * 0.35;
  if (rd.y > 0.05) {
    let sp = rd.xz / (rd.y + 0.2);
    let stars = hash21(floor(sp * 40.0));
    c += vec3f(step(0.995, stars)) * 0.8 * smoothstep(0.05, 0.30, rd.y);
  }
  return c;
}

fn nc_facade(p: vec3f, n: vec3f, cell: vec2f) -> vec3f {
  let baseCol = vec3f(0.018, 0.022, 0.035);
  if (abs(n.y) > 0.55) { return vec3f(0.012, 0.016, 0.026); }
  var u = p.z;
  if (abs(n.z) > abs(n.x)) { u = p.x; }
  let WU = 1.05;  let WV = 1.35;
  let cu = floor(u / WU);
  let cv = floor((p.y - 0.6) / WV);
  let fu = fract(u / WU);
  let fv = fract((p.y - 0.6) / WV);
  let inWin = step(0.18, fu) * step(fu, 0.82) * step(0.20, fv) * step(fv, 0.86) * step(0.6, p.y);
  let r = hash21(cell * 7.0 + vec2f(cu * 1.3, cv * 2.1));
  let lit = step(0.48, r);
  let cyan = step(0.86, hash21(cell + vec2f(cu, cv) * 0.7));
  let wc = mix(vec3f(1.70, 1.20, 0.62), vec3f(0.45, 1.50, 1.80), cyan);
  return baseCol + wc * lit * inWin * 2.4;
}

fn nc_ballBody(flash: f32) -> vec3f {
  let held = clamp(uni(8), 0.0, 1.0);   // grabbed: the ball runs blue
  let hurt = clamp(uni(10), 0.0, 1.0);  // bitten: it stings red
  var c = mix(vec3f(3.0, 1.7, 0.8), vec3f(7.0, 5.5, 4.0), flash);
  let cb = mix(vec3f(0.5, 1.8, 3.4), vec3f(4.0, 5.5, 7.0), flash);
  c = mix(c, cb, held);
  return mix(c, vec3f(6.0, 0.35, 0.25), hurt);
}

fn nc_ballGlow(ro: vec3f, rd: vec3f, ball: vec3f, sceneT: f32, flash: f32) -> vec3f {
  let oc = ball - ro;
  let tca = dot(oc, rd);
  if (tca < 0.0) { return vec3f(0.0); }
  let d2x = dot(oc, oc) - tca * tca;
  // occluded: a faint pulse bleeds through the towers — the toy is never lost
  if (tca > sceneT + 2.0) { return mix(vec3f(1.3, 0.55, 0.28), vec3f(0.35, 0.80, 1.60), clamp(uni(8), 0.0, 1.0)) * exp(-d2x * 0.030) * (0.12 + flash * 0.3); }
  let d2 = dot(oc, oc) - tca * tca;
  let trail = ball - normalize(vec3f(uni(5), uni(6), uni(7)) + vec3f(1.0e-5)) * 2.4;
  let oc2 = trail - ro;
  let tca2 = dot(oc2, rd);
  var g = exp(-d2 * 0.10) * (0.8 + flash * 1.6);
  if (tca2 > 0.0 && tca2 < sceneT + 2.0) {
    g += exp(-(dot(oc2, oc2) - tca2 * tca2) * 0.16) * 0.30;
  }
  return mix(vec3f(1.7, 1.0, 0.5), vec3f(0.45, 1.00, 1.90), clamp(uni(8), 0.0, 1.0)) * g;
}

fn nc_reflColor(ro: vec3f, rd: vec3f, ball: vec3f, flash: f32) -> array<vec3f, 2> {
  let hb = nc_traceCity(ro, rd, 110.0, 20);
  var sceneT = hb.t;
  var c: vec3f;
  let tc = nc_sphereT(ro, rd, ball, 1.3);
  if (tc > 0.0 && tc < sceneT) {
    c = nc_ballBody(flash);
    sceneT = tc;
  } else if (hb.kind == 1) {
    let p = ro + rd * hb.t;
    c = mix(nc_facade(p, hb.n, hb.cell), nc_sky(rd), 1.0 - exp(-hb.t * 0.02));
  } else if (hb.kind == 0) {
    c = vec3f(0.02, 0.022, 0.03);
  } else {
    c = nc_sky(rd);
  }
  return array<vec3f, 2>(c, nc_ballGlow(ro, rd, ball, sceneT, flash));
}

fn visual_nc_city(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = vec2f(uv.x, -uv.y);
  let t = time;
  let district = nc_mode() > 0.5;

  var camZ = uni(0);
  if (camZ < 0.001) { camZ = t * 5.0; }

  var ro: vec3f;
  var look: vec3f;
  if (district) {                          // street level, dollying down the path
    ro = vec3f(4.5, 5.6, uni(26));         // the hook publishes the dolly (uni 26)
    look = normalize(vec3f(0.0, -0.10, 1.0));   // hand math mirrors this exactly
  } else {                                 // the drive: low, forward, swaying
    ro = vec3f(4.5 + sin(t * 0.08) * 1.2, 5.2 + sin(t * 0.20) * 0.30, camZ);
    look = normalize(vec3f(sin(t * 0.05) * 0.12, -0.12, 1.0));
  }
  let rt = normalize(cross(vec3f(0.0, 1.0, 0.0), look));
  let up = cross(look, rt);
  var rd = normalize(rt * p.x + up * (p.y * 0.72) + look * 1.5);
  rd = normalize(rd + vec3f(1.0e-4));

  var ball = nc_ball();
  if (ball.y < 0.01) { ball = vec3f(4.5, 2.0, camZ + 20.0); }
  let flash = uni(4);
  let horizon = nc_sky(vec3f(rd.x, max(rd.y, 0.02), rd.z));
  var col = nc_sky(rd);

  let hit = nc_traceCity(ro, rd, 220.0, 44);
  var hitT = hit.t;
  var kind = hit.kind;

  let tc = nc_sphereT(ro, rd, ball, 1.3);
  if (tc > 0.0 && tc < hitT) { hitT = tc; kind = 2; }

  // enemies — red hunters coming up the street (uni 16..24; 0 = empty slot)
  var eHit = -1;
  if (district) {
    for (var ei = 0; ei < 3; ei++) {
      let e = vec3f(uni(16 + ei * 3), uni(17 + ei * 3), uni(18 + ei * 3));
      if (e.y < 0.01) { continue; }
      let te = nc_sphereT(ro, rd, e, 1.5);
      if (te > 0.0 && te < hitT) { hitT = te; kind = 4; eHit = ei; }
    }
  }

  if (kind == 4) {
    let e = vec3f(uni(16 + eHit * 3), uni(17 + eHit * 3), uni(18 + eHit * 3));
    let hp = ro + rd * hitT;
    let nn = normalize(hp - e);
    let rim = pow(1.0 - max(dot(nn, -rd), 0.0), 2.0);
    let beat = 0.75 + 0.25 * sin(t * 6.0 + f32(eHit) * 2.1);
    col = vec3f(2.4, 0.16, 0.12) * beat + vec3f(3.0, 0.5, 0.25) * rim;
  } else if (kind == 2) {
    let hp = ro + rd * hitT;
    let nn = normalize(hp - ball);
    let rim = pow(1.0 - max(dot(nn, -rd), 0.0), 2.0);
    col = nc_ballBody(flash) + mix(vec3f(1.2, 0.6, 0.25), vec3f(0.3, 0.8, 1.6), clamp(uni(8), 0.0, 1.0)) * rim;
  } else if (kind == 1) {
    let hp = ro + rd * hitT;
    var mcol = nc_facade(hp, hit.n, hit.cell);
    mcol += nc_sky(hit.n) * 0.04;
    col = mix(mcol, horizon, 1.0 - exp(-hitT * 0.014));
  } else if (kind == 0) {
    let hp = ro + rd * hitT;
    let rip = vnoise(hp.xz * 0.8 + vec2f(0.0, t * 0.3)) - 0.5;
    let rn = normalize(vec3f(rip * 0.08, 1.0, rip * 0.08));
    let rrd = normalize(reflect(rd, rn) + vec3f(1.0e-4));
    let refl = nc_reflColor(hp + rn * 0.05, rrd, ball, flash);
    let fres = pow(1.0 - max(-rd.y, 0.0), 4.0);
    var road = mix(vec3f(0.015, 0.017, 0.024), refl[0], clamp(fres * 0.7 + 0.15, 0.0, 1.0));
    road += refl[1] * 0.65;
    col = mix(road, horizon, 1.0 - exp(-hitT * 0.014));
  }

  col += nc_ballGlow(ro, rd, ball, hitT, flash);

  if (district) {
    // enemy glow + the red sting when one gets through
    for (var gi = 0; gi < 3; gi++) {
      let e = vec3f(uni(16 + gi * 3), uni(17 + gi * 3), uni(18 + gi * 3));
      if (e.y < 0.01) { continue; }
      let oc2 = e - ro;
      let tca = dot(oc2, rd);
      if (tca > 0.0 && tca < hitT + 3.0) {
        let dsq = max(dot(oc2, oc2) - tca * tca, 0.0);
        col += vec3f(2.2, 0.2, 0.14) * exp(-dsq * 0.6) * 0.35;
      }
    }
    col += vec3f(1.4, 0.06, 0.04) * uni(25) * pow(length(p), 2.0) * 0.8;
    // the bite: red sting from the edges. the win: the city turns gold
    col += vec3f(1.6, 0.05, 0.04) * uni(10) * pow(length(p), 2.0);
    let win = clamp(uni(11), 0.0, 1.0);
    col = mix(col, col * vec3f(1.35, 1.18, 0.75) + vec3f(0.20, 0.15, 0.04), win * 0.55);
  }

  return vec4f(col, 1.0);
}

fn cf_portal_pos(i: i32) -> vec2f {
  if (i == 0) { return vec2f(0.073, 0.021); }
  if (i == 1) { return vec2f(-0.179, -0.008); }
  if (i == 2) { return vec2f(0.16, -0.15); }
  if (i == 3) { return vec2f(0.001, 0.19); }
  if (i == 4) { return vec2f(-0.219, -0.196); }
  if (i == 5) { return vec2f(0.357, 0.002); }
  if (i == 6) { return vec2f(-0.309, 0.157); }
  if (i == 7) { return vec2f(0.071, -0.326); }
  if (i == 8) { return vec2f(0.242, 0.259); }
  if (i == 9) { return vec2f(-0.458, -0.11); }
  if (i == 10) { return vec2f(0.442, -0.191); }
  if (i == 11) { return vec2f(-0.177, 0.344); }
  return vec2f(0.0, 0.0);
}
fn cf_style(i: i32) -> i32 {
  if (i == 0) { return 8; }
  if (i == 1) { return 2; }
  if (i == 2) { return 8; }
  if (i == 3) { return 8; }
  if (i == 4) { return 8; }
  if (i == 5) { return 6; }
  if (i == 6) { return 7; }
  if (i == 7) { return 8; }
  if (i == 8) { return 8; }
  if (i == 9) { return 8; }
  if (i == 10) { return 1; }
  if (i == 11) { return 0; }
  return 8;
}
fn cf_hue(i: i32) -> f32 {
  if (i == 0) { return 0.420; }
  if (i == 1) { return 0.980; }
  if (i == 2) { return 0.660; }
  if (i == 3) { return 0.990; }
  if (i == 4) { return 0.160; }
  if (i == 5) { return 0.130; }
  if (i == 6) { return 0.400; }
  if (i == 7) { return 0.760; }
  if (i == 8) { return 0.960; }
  if (i == 9) { return 0.250; }
  if (i == 10) { return 0.050; }
  if (i == 11) { return 0.720; }
  return 0.5;
}

fn cf_stars(p: vec2f, t: f32) -> vec3f {
  var c = vec3f(0.008, 0.007, 0.016);
  c += vec3f(0.05, 0.025, 0.09) * smoothstep(0.4, 0.9, fbm(p * 1.5 + vec2f(t * 0.004, 0.0), 4));
  for (var l = 0; l < 2; l++) {
    let fl = f32(l);
    let sp = p * (16.0 + fl * 26.0) + fl * 31.0;
    let cell = floor(sp);
    let h = hash21(cell);
    let fp = fract(sp) - 0.5;
    let tw = 0.5 + 0.5 * sin(t * (0.5 + h * 1.4) + h * 40.0);
    c += vec3f(0.8, 0.75, 0.95) * step(0.985, h) * smoothstep(0.24, 0.03, length(fp)) * tw * (1.1 - fl * 0.4);
  }
  return c;
}

fn visual_cf_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let mp = vec2f(uni(0), uni(1));     // cursor in field coords

  // ── the room: stars seen through curved space (your cursor is a lens) ──
  var p = uv;
  let md = uv - mp;
  let mr2 = max(dot(md, md), 0.002);
  p -= md * (0.010 / mr2) * smoothstep(0.9, 0.2, length(md));
  var col = cf_stars(p, t);

  // warm hearth-light from below — this is a cafe, not a void
  col += vec3f(0.10, 0.055, 0.02) * pow(max(0.0, uv.y + 0.2), 2.0) * (0.8 + 0.2 * sin(t * 0.7));

  // ── every cartridge on the shelf, newest nearest the center ──
  for (var i = 0; i < 12; i++) {
    let ctr = cf_portal_pos(i);
    let d = length(uv - ctr);
    let R = 0.088;
    let hov = uni(2 + i);                          // 0..1 hover bloom from the hook
    let rr = R * (1.0 + hov * 0.12);
    if (d < rr) {
      let q = (uv - ctr) / rr;                     // -1..1 inside the disc
      var g = vec3f(0.0);
      let st = cf_style(i);
      if (st == 0) {
        // FABRIC — a lens wandering through stars
        var pp = q * 2.0;
        let lc = vec2f(sin(t * 0.6) * 0.5, cos(t * 0.47) * 0.4);
        let ld = pp - lc;
        pp -= ld * (0.16 / max(dot(ld, ld), 0.02));
        g = cf_stars(pp * 1.6, t) * 2.2;
        g += vec3f(0.5, 0.9, 1.1) * exp(-dot(ld, ld) * 14.0) * 0.4;
      } else if (st == 1) {
        // ORRERY — three worlds around a coal
        g = vec3f(0.02, 0.015, 0.03);
        g += vec3f(3.0, 1.7, 0.5) * exp(-dot(q, q) * 30.0);
        for (var k = 1; k <= 3; k++) {
          let fk = f32(k);
          let a = t * (0.9 - fk * 0.18) + fk * 2.1;
          let pp = q - vec2f(cos(a), sin(a)) * (0.22 + fk * 0.17);
          var pc = vec3f(0.45, 0.5, 0.65);
          if (k == 2) { pc = vec3f(0.2, 0.45, 0.8); }
          if (k == 3) { pc = vec3f(0.8, 0.5, 0.25); }
          g += pc * exp(-dot(pp, pp) * 260.0) * 1.6;
        }
      } else if (st == 2) {
        // GARNET — the crystal
        let qa = rotate(q, t * 0.4);
        let cd = abs(qa.x) * 0.866 + abs(qa.y) * 0.5;
        let inside = smoothstep(0.62, 0.58, max(cd, abs(qa.y)));
        let facet = 0.6 + 0.4 * sin(qa.x * 9.0 + qa.y * 7.0 + t * 0.8);
        g = mix(vec3f(0.02, 0.01, 0.02), vec3f(0.75, 0.18, 0.25) * facet, inside);
        g += vec3f(1.6, 0.9, 0.7) * pow(max(0.0, facet - 0.75) * 4.0, 2.0) * inside;
      } else if (st == 3) {
        // ONE DAY — a sky that keeps its whole day
        let ph = fract(t * 0.05);
        let el = sin(ph * 6.28318) * 0.8;
        let day = smoothstep(-0.2, 0.4, el);
        g = mix(vec3f(0.02, 0.02, 0.06), vec3f(0.25, 0.5, 0.8), day * (0.5 - q.y * 0.5));
        g = mix(g, vec3f(0.9, 0.4, 0.15), smoothstep(0.3, 0.0, abs(el)) * max(0.0, -q.y + 0.2) * 0.9);
        let sun = vec2f(cos(ph * 6.28318 - 1.57) * 0.6, -el * 0.55 + 0.1);
        g += vec3f(3.0, 2.0, 0.9) * exp(-dot(q - sun, q - sun) * 60.0) * max(day, 0.15);
        if (q.y > 0.25) { g = mix(g, g * vec3f(0.5, 0.6, 0.8), 0.6); }   // the sea below
      } else if (st == 4) {
        // SAIL — one boat, one sea
        g = mix(vec3f(0.35, 0.5, 0.65), vec3f(0.05, 0.14, 0.2), smoothstep(-0.1, 0.5, q.y));
        let w = sin(q.x * 9.0 + t * 1.4) * 0.05;
        g = mix(g, vec3f(0.03, 0.10, 0.14), smoothstep(w + 0.02, w - 0.02, -q.y + 0.1) * 0.0 + smoothstep(w - 0.02, w + 0.06, q.y - 0.05));
        let sail = max(max(-(q.x + 0.05) * 3.0, q.y + 0.15), (q.x * 0.9 + q.y * 0.8) - 0.28);
        g = mix(g, vec3f(1.0, 0.96, 0.88), smoothstep(0.02, -0.02, sail));
      } else if (st == 5) {
        // SOLSTICE — a sun you carry over a valley
        g = vec3f(0.03, 0.04, 0.09);
        let sp = vec2f(sin(t * 0.5) * 0.45, -0.3 + cos(t * 0.5) * 0.12);
        g += vec3f(3.2, 2.2, 0.9) * exp(-dot(q - sp, q - sp) * 40.0);
        let hill = q.y - (0.25 + 0.15 * sin(q.x * 3.0 + 1.0));
        let lit = max(0.0, 1.0 - length(q - sp) * 1.4);
        g = mix(g, mix(vec3f(0.03, 0.05, 0.02), vec3f(0.15, 0.3, 0.08), lit), smoothstep(-0.02, 0.02, hill));
      } else if (st == 6) {
        // TIDERUNNER — wind over water
        let band = sin(q.y * 14.0 - t * 1.1 + sin(q.x * 4.0) * 0.7);
        g = mix(vec3f(0.05, 0.13, 0.17), vec3f(0.12, 0.25, 0.3), 0.5 + 0.5 * band);
        g += vec3f(0.8, 0.85, 0.85) * pow(max(0.0, band - 0.8) * 5.0, 2.0) * 0.4;
        let bt = q - vec2f(sin(t * 0.4) * 0.4, 0.0);
        g += vec3f(0.9, 0.85, 0.75) * exp(-dot(bt, bt) * 300.0) * 1.2;
      } else if (st == 7) {
        // SIGNAL — a television waiting for a word
        let sn = hash21(floor(q * 24.0) + floor(t * 9.0));
        g = vec3f(sn * 0.5);
        g += vec3f(0.3, 1.0, 0.45) * exp(-dot(q, q) * 8.0) * (0.28 + 0.14 * sin(t * 2.0));
        g *= 0.82 + 0.18 * sin(q.y * 60.0 - t * 8.0);
      } else {
        // a young world — a banded seed-planet in its own hue
        let hue = cf_hue(i);
        let cA = 0.5 + 0.5 * cos(6.2831 * (hue + vec3f(0.0, 0.33, 0.67)));
        g = cA * (0.22 + 0.5 * fbm3(q * 3.0 + vec2f(t * 0.08, f32(i) * 3.7)));
        g += cA * 0.4 * smoothstep(0.6, 1.0, 1.0 - abs(q.y * 2.2 + 0.3 * sin(q.x * 3.0 + t * 0.4)));
        let mn = q - vec2f(cos(t * 0.5 + f32(i) * 1.9), sin(t * 0.5 + f32(i) * 1.9) * 0.6) * 0.78;
        g += vec3f(0.85) * exp(-dot(mn, mn) * 260.0);
        g *= 0.85 + 0.3 * (1.0 - length(q));
      }
      // glass edge + hover bloom
      let edge = smoothstep(1.0, 0.86, length(q));
      col = mix(col, g, edge);
      col += vec3f(1.2, 0.85, 0.4) * exp(-pow((length(q) - 0.97) * 9.0, 2.0)) * (0.25 + hov * 1.3);
    } else {
      // halo when hovered
      col += vec3f(1.0, 0.7, 0.3) * exp(-pow((d - rr) * 22.0, 2.0)) * hov * 0.8;
    }
  }

  // the cursor itself — a soft ember
  col += vec3f(1.4, 0.9, 0.4) * exp(-dot(uv - mp, uv - mp) * 900.0) * 0.8;

  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(60.0)), 1.0);
}

fn ch_dream(q: vec2f, t: f32) -> vec3f {
  // CH 5 — the set dreams the worlds it has seen
  let drift = fbm3(q * 1.6 + vec2f(t * 0.05, -t * 0.03));
  var col = mix(vec3f(0.02, 0.03, 0.06), vec3f(0.10, 0.07, 0.16), drift);
  let s = vnoise(q * 3.0 + vec2f(sin(t * 0.2) * 2.0, t * 0.11));
  col += vec3f(0.25, 0.2, 0.5) * pow(s, 3.0);
  let mem = floor(t / 8.0) % 4.0;
  let ph = smoothstep(0.0, 0.15, fract(t / 8.0)) * smoothstep(1.0, 0.85, fract(t / 8.0));
  if (mem < 0.5) {          // a sun that was carried across a sky
    col += vec3f(2.0, 1.3, 0.4) * exp(-length(q - vec2f(sin(t * 0.13) * 0.4, -0.2)) * 5.0) * ph;
  } else if (mem < 1.5) {   // the hex lattice
    let hx = abs(fract(q.x * 4.0 + q.y * 2.0) - 0.5) * abs(fract(q.y * 4.6) - 0.5);
    col += vec3f(0.2, 0.9, 0.8) * smoothstep(0.22, 0.25, hx) * 0.35 * ph;
  } else if (mem < 2.5) {   // city windows in the rain
    let w = step(0.6, hash21(floor(q * vec2f(14.0, 10.0)) + floor(t * 0.5)));
    col += vec3f(1.4, 1.0, 0.5) * w * 0.3 * ph;
  } else {                  // a beam crossing a sun, water catching fire
    let ang = atan2(q.y + 0.3, q.x);
    col += vec3f(1.8, 1.6, 1.1) * exp(-abs(ang - sin(t * 0.3)) * 8.0) * exp(-length(q) * 1.2) * ph * 0.7;
    col += vec3f(2.2, 0.8, 0.2) * exp(-length(q - vec2f(cos(t * 0.3), -0.3 + sin(t * 0.3) * 0.2)) * 6.0) * ph;
  }
  return col;
}

// ── the channel words: each is a callable shader — signature (q: -1..1 screen, t) ──

fn ch_static(q: vec2f, t: f32) -> vec3f {
  let n = hash21(floor(q * vec2f(160.0, 120.0)) + floor(t * 60.0) * 7.3);
  var v = 0.25 + 0.75 * n;
  // rolling tear bar
  let bar = fract(q.y * 0.5 - t * 0.35);
  if (bar < 0.06) { v *= 0.45; }
  return vec3f(v);
}

fn ch_plasma(q: vec2f, t: f32) -> vec3f {
  var v = sin(q.x * 6.0 + t * 1.2);
  v += sin((q.y * 5.0 + t) * 0.8);
  v += sin((q.x + q.y) * 4.0 + t * 0.7);
  v += sin(length(q * 5.0) - t * 1.5);
  v *= 0.25;
  return vec3f(0.5 + 0.5 * sin(6.2831 * v), 0.5 + 0.5 * sin(6.2831 * v + 2.1), 0.5 + 0.5 * sin(6.2831 * v + 4.2));
}

fn ch_pong(q: vec2f, t: f32) -> vec3f {
  var col = vec3f(0.02, 0.03, 0.02);
  // net
  if (abs(q.x) < 0.012 && fract(q.y * 5.0) < 0.55) { col = vec3f(0.35); }
  // paddles (hook-simulated)
  if (abs(q.x + 0.85) < 0.03 && abs(q.y - uni(5)) < 0.16) { col = vec3f(1.4); }
  if (abs(q.x - 0.85) < 0.03 && abs(q.y - uni(6)) < 0.16) { col = vec3f(1.4); }
  // ball
  if (abs(q.x - uni(3)) < 0.035 && abs(q.y - uni(4)) < 0.045) { col = vec3f(1.8); }
  // score pips
  for (var i = 0; i < 5; i++) {
    if (f32(i) < uni(7) && length(q - vec2f(-0.5 + f32(i) * 0.08, -0.85)) < 0.022) { col = vec3f(1.0); }
    if (f32(i) < uni(8) && length(q - vec2f(0.5 - f32(i) * 0.08, -0.85)) < 0.022) { col = vec3f(1.0); }
  }
  return col;
}

fn ch_boids(q: vec2f, t: f32) -> vec3f {
  var col = mix(vec3f(0.03, 0.05, 0.10), vec3f(0.10, 0.14, 0.22), q.y * -0.5 + 0.5);
  // moon
  col += vec3f(0.5, 0.5, 0.42) * exp(-length(q - vec2f(0.55, -0.55)) * 9.0);
  // the flock (hook-simulated)
  for (var i = 0; i < 16; i++) {
    let b = vec2f(uni(10 + i * 2), uni(11 + i * 2));
    let d = length(q - b);
    if (d < 0.028) { col = vec3f(0.02); }                    // bird body
    col += vec3f(0.05, 0.05, 0.04) * exp(-d * 40.0);         // faint presence
  }
  return col;
}


fn sc_box(p: vec2f, c: vec2f, b: vec2f, r: f32) -> f32 {
  let d = abs(p - c) - b;
  return length(max(d, vec2f(0.0))) + min(max(d.x, d.y), 0.0) - r;
}

// CH 5 — SITCOM. The hook runs four little lives through behavior zones
// (couch, kitchen, window, door, center-stage); the tube just draws them.
fn ch_sitcom(q: vec2f, t: f32) -> vec3f {
  let FLOOR = 0.42;
  // the set: warm wall, wood floor
  var col = mix(vec3f(0.20, 0.14, 0.11), vec3f(0.13, 0.09, 0.08), q.y * 0.5 + 0.5);
  col *= 0.94 + 0.06 * sin(q.x * 40.0);
  if (q.y > FLOOR) {
    col = mix(vec3f(0.17, 0.11, 0.06), vec3f(0.10, 0.06, 0.04), (q.y - FLOOR) * 1.6);
    col *= 0.9 + 0.1 * sin(q.x * 24.0 + q.y * 60.0);
  }
  // window on the night
  let wd2 = sc_box(q, vec2f(-0.72, -0.28), vec2f(0.13, 0.17), 0.02);
  if (wd2 < 0.0) {
    col = vec3f(0.02, 0.03, 0.07);
    if (hash21(floor(q * 30.0)) > 0.992) { col += vec3f(0.6); }
    col += vec3f(0.35, 0.35, 0.30) * exp(-length(q - vec2f(-0.68, -0.38)) * 14.0);
    if (abs(q.x + 0.72) < 0.012 || abs(q.y + 0.28) < 0.012) { col = vec3f(0.24, 0.17, 0.12); }
  } else if (wd2 < 0.02) { col = vec3f(0.26, 0.19, 0.13); }
  // the door — uni(2) swings it open on a dark hallway
  let dOpen = uni(2);
  let dframe = sc_box(q, vec2f(0.86, 0.12), vec2f(0.11, 0.30), 0.01);
  if (dframe < 0.0) {
    col = vec3f(0.03, 0.025, 0.032);
    if (q.x > 0.75 + dOpen * 0.17) {
      col = vec3f(0.23, 0.15, 0.09) * (0.85 + 0.15 * sin(q.y * 30.0));
      if (length(q - vec2f(0.78 + dOpen * 0.17, 0.14)) < 0.012) { col = vec3f(0.55, 0.45, 0.25); }
    }
  } else if (dframe < 0.018) { col = vec3f(0.28, 0.20, 0.13); }
  // couch
  let cc = vec2f(-0.30, 0.32);
  if (sc_box(q, cc + vec2f(0.0, -0.10), vec2f(0.27, 0.09), 0.04) < 0.0) { col = vec3f(0.36, 0.11, 0.11); }
  if (sc_box(q, cc + vec2f(0.0, 0.05), vec2f(0.27, 0.06), 0.04) < 0.0) {
    col = vec3f(0.45, 0.14, 0.13);
    if (abs(q.x - cc.x) < 0.004) { col *= 0.8; }
  }
  if (sc_box(q, cc + vec2f(-0.30, 0.0), vec2f(0.035, 0.12), 0.03) < 0.0 ||
      sc_box(q, cc + vec2f(0.30, 0.0), vec2f(0.035, 0.12), 0.03) < 0.0) { col = vec3f(0.42, 0.13, 0.12); }
  // kitchen counter + mug
  if (sc_box(q, vec2f(0.52, 0.47), vec2f(0.14, 0.08), 0.01) < 0.0) { col = vec3f(0.20, 0.16, 0.12); }
  if (sc_box(q, vec2f(0.52, 0.385), vec2f(0.155, 0.014), 0.005) < 0.0) { col = vec3f(0.55, 0.50, 0.42); }
  if (sc_box(q, vec2f(0.47, 0.355), vec2f(0.012, 0.014), 0.004) < 0.0) { col = vec3f(0.75, 0.68, 0.60); }
  // lamp
  if (abs(q.x - 0.13) < 0.006 && q.y > -0.02 && q.y < FLOOR) { col = vec3f(0.1); }
  if (q.y > -0.11 && q.y < -0.02 && abs(q.x - 0.13) < 0.035 + (q.y + 0.11) * 0.45) { col = vec3f(0.85, 0.65, 0.35); }
  col += vec3f(0.5, 0.35, 0.15) * exp(-length((q - vec2f(0.13, 0.05)) * vec2f(1.0, 0.8)) * 3.2) * 0.35;

  // ── the cast (uni 42..61: x, pose, face, talk, row per character) ──
  for (var i = 0; i < 4; i++) {
    let ux = uni(42 + i * 5);
    let pose = uni(43 + i * 5);
    if (pose > 2.5) { continue; }
    let face = uni(44 + i * 5);
    let talk = uni(45 + i * 5);
    let row = uni(46 + i * 5);
    let fi = f32(i);
    var shirt = vec3f(0.75, 0.55, 0.15);
    var hair = vec3f(0.12, 0.09, 0.05);
    if (i == 1) { shirt = vec3f(0.15, 0.50, 0.50); hair = vec3f(0.35, 0.20, 0.08); }
    if (i == 2) { shirt = vec3f(0.55, 0.22, 0.10); hair = vec3f(0.08, 0.08, 0.08); }
    if (i == 3) { shirt = vec3f(0.35, 0.18, 0.42); hair = vec3f(0.50, 0.45, 0.40); }
    let hgt = 0.30 + fi * 0.014;
    let sitting = pose > 1.5;
    let walking = abs(pose - 1.0) < 0.25;
    let bob = select(0.0, abs(sin(t * 7.0 + fi * 2.0)) * 0.012, walking);
    let feetY = select(FLOOR + row, 0.40, sitting) - bob;
    let hipY = feetY - select(hgt * 0.42, 0.055, sitting);
    let torsoC = vec2f(ux, hipY - hgt * 0.19);
    let headC = vec2f(ux + face * 0.008, hipY - hgt * 0.36);
    if (sitting) {
      if (sc_box(q, vec2f(ux + face * 0.05, hipY + 0.05), vec2f(0.05, 0.015), 0.01) < 0.0) { col = vec3f(0.14, 0.13, 0.18); }
    } else {
      let sw = select(0.0, sin(t * 9.0 + fi * 2.0) * 0.016, walking);
      if (sc_box(q, vec2f(ux - 0.014 + sw, (hipY + feetY) * 0.5), vec2f(0.010, (feetY - hipY) * 0.5), 0.006) < 0.0 ||
          sc_box(q, vec2f(ux + 0.014 - sw, (hipY + feetY) * 0.5), vec2f(0.010, (feetY - hipY) * 0.5), 0.006) < 0.0) { col = vec3f(0.14, 0.13, 0.18); }
    }
    if (sc_box(q, torsoC, vec2f(0.036, hgt * 0.20), 0.02) < 0.0) { col = shirt; }
    let hd = length(q - headC);
    if (hd < 0.036) { col = vec3f(0.85, 0.62, 0.45); }
    if (hd < 0.038 && q.y < headC.y - 0.010) { col = hair; }
    if (fract(t * 0.31 + fi * 0.37) > 0.06) {
      if (length(q - (headC + vec2f(face * 0.012 - 0.008, 0.004))) < 0.0035 ||
          length(q - (headC + vec2f(face * 0.012 + 0.008, 0.004))) < 0.0035) { col = vec3f(0.05, 0.05, 0.05); }
    }
    if (talk > 0.5) {
      let bc = headC + vec2f(face * 0.11, -0.105);
      let bd = sc_box(q, bc, vec2f(0.065, 0.030), 0.02);
      if (bd < 0.0) {
        col = vec3f(0.92, 0.92, 0.90);
        for (var k = 0; k < 3; k++) {
          if (fract(t * 0.9 + fi * 0.5) > f32(k) * 0.3 &&
              length(q - (bc + vec2f(-0.03 + f32(k) * 0.03, 0.0))) < 0.008) { col = vec3f(0.25, 0.25, 0.25); }
        }
      } else if (bd < 0.006 && bd >= 0.0) { col = vec3f(0.6, 0.6, 0.58); }
    }
  }
  // the laugh: warm audience light washing up from below
  col += vec3f(0.45, 0.32, 0.12) * uni(62) * (0.6 + 0.4 * sin(t * 18.0)) * (0.3 + 0.7 * smoothstep(0.0, 0.8, q.y));
  return col;
}

fn visual_tv_set(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = (uv + vec2f(1.0)) * 256.0;
  let t = time;

  // the room: dark, lit by the set
  var col = vec3f(0.012, 0.011, 0.015) * (1.0 + 0.35 * fbm3(p * 0.01));

  let C = vec2f(256.0, 238.0);
  let half = vec2f(172.0, 122.0);
  let dBez = sdRoundedBox(p - C, half + vec2f(22.0, 26.0), 14.0);
  let dScr = sdRoundedBox(p - C, half, 10.0);

  // glow spill on the room
  let flick = 0.94 + 0.06 * sin(t * 47.0) * sin(t * 31.0);
  col += vec3f(0.10, 0.12, 0.16) * flick * exp(-max(dBez, 0.0) * 0.02);

  // bezel: warm plastic with a highlight
  if (dBez < 0.0 && dScr >= 0.0) {
    col = mix(vec3f(0.10, 0.085, 0.07), vec3f(0.16, 0.14, 0.12), fbm3(p * 0.15) * 0.5);
    col *= 0.8 + 0.4 * smoothstep(20.0, -30.0, p.y - (C.y - half.y));
    // channel knob
    let kd = length(p - (C + vec2f(half.x + 8.0, half.y + 14.0)));
    if (kd < 7.0) {
      col = vec3f(0.05);
      let ka = 6.2831 * uni(0) / 5.0 - 1.57;
      if (length(p - (C + vec2f(half.x + 8.0, half.y + 14.0)) - vec2f(cos(ka), sin(ka)) * 4.0) < 1.6) { col = vec3f(0.7); }
    }
  }

  // the screen: barrel-distorted, phosphor, scanlines — a CRT calling a channel
  if (dScr < 0.0) {
    var q = (p - C) / half;                                   // -1..1
    q *= 1.0 + 0.10 * dot(q, q);                              // barrel
    if (abs(q.x) > 1.0 || abs(q.y) > 1.0) {
      col = vec3f(0.0);                                       // over-scan black
    } else {
      // ── THE CALL: channel word by number ──
      let ch = i32(uni(0) + 0.5);
      var scr: vec3f;
      if (ch == 0) { scr = ch_static(q, t); }
      else if (ch == 1) { scr = ch_plasma(q, t); }
      else if (ch == 2) { scr = ch_pong(q, t); }
      else if (ch == 3) { scr = ch_boids(q, t); }
      else { scr = ch_sitcom(q, t); }

      // switch burst: static bleeds over the program
      if (uni(1) > 0.01) { scr = mix(scr, ch_static(q, t * 3.0), min(uni(1) * 1.4, 1.0)); }

      // CRT dress: phosphor triads, scanlines, corner falloff, flicker
      let px = i32(p.x * 3.0) % 3;
      var mask = vec3f(0.85);
      if (px == 0) { mask = vec3f(1.25, 0.72, 0.72); }
      else if (px == 1) { mask = vec3f(0.72, 1.25, 0.72); }
      else { mask = vec3f(0.72, 0.72, 1.25); }
      scr *= mask;
      scr *= 0.82 + 0.18 * sin(p.y * 3.14159);                // scanlines
      scr *= flick;
      scr *= 1.0 - 0.45 * pow(length(q), 4.0);                // corner falloff
      col = scr * 1.35;                                       // HDR — bloom catches the tube
    }
  }

  // set shadow on the floor
  col *= 1.0 - 0.3 * smoothstep(30.0, 0.0, abs(p.y - (C.y + half.y + 40.0))) * smoothstep(half.x + 40.0, half.x - 20.0, abs(p.x - C.x));

  return vec4f(col, 1.0);
}
